def title_words(s):
    if not s:
        return ''

    words = s.split()
    titled_words = []

    for word in words:
        if word.isupper():
            titled_words.append(word)
        else:
            titled_words.append(word.title())

    return ' '.join(titled_words)

# Edge Case: Empty string
print(title_words(""))  # Output: ''
